# 功能名称：记忆管理中心
# 原始需求：向记忆树增删节点、建立关系、触发衰减、查看活跃记忆、输出维护建议、节点凝练
# 设计思路：v0.3标准，4种类型，阶段性衰减+保护期+锚定缓冲，维护建议一键确认，手动凝练
# 注意事项：衰减不叠加，按最长时间段单次触发；保护期每次使用重置30天；boundary/unresolved永不衰减
# 后续优化：支持场景标签编辑，支持半自动建节点
# @AI_MEMO_END

from datetime import datetime, timedelta

VALID_TYPES = {"边界","未解决","决策","事实"}
TYPE_LABEL = {"边界":"边界","未解决":"未解决","决策":"决策","事实":"事实"}
NO_DECAY = {"边界","未解决"}

def _get_anchored_ids(nodes):
    anchored = set()
    for n in nodes.values():
        for r in n.get("relations",[]):
            anchored.add(r.get("target",""))
    return anchored

def _mem_add(data):
    print("\n--- 新增记忆节点 ---")
    print("类型: 1.边界  2.未解决  3.决策  4.事实")
    t_map = {"1":"边界","2":"未解决","3":"决策","4":"事实"}
    t_idx = input("选择类型(1-4): ").strip()
    n_type = t_map.get(t_idx)
    if not n_type:
        print("❌ 类型无效"); return data
    content = input("内容: ").strip()
    if not content:
        print("❌ 内容不能为空"); return data
    print("场景标签（逗号分隔，可选）：系统架构/开发实践/记忆树/身份原则/AI协作")
    tags_input = input("标签: ").strip()
    scenario_tags = [t.strip() for t in tags_input.split(",") if t.strip()] if tags_input else []
    default_weights = {"边界":1.0,"未解决":1.0,"决策":0.9,"事实":0.8}
    now_str = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    protect_until = (datetime.now() + timedelta(days=30)).strftime("%Y-%m-%d")
    n_id = datetime.now().strftime("%y%m%d%H%M%S") + "_" + n_type[:2]
    node = {
        "id": n_id,
        "type": n_type,
        "content": content,
        "weight": default_weights[n_type],
        "status": "active",
        "time": now_str,
        "updated": now_str,
        "protected_until": protect_until,
        "use_count": 0,
        "relations": [],
        "tags": [],
        "scenario_tags": scenario_tags
    }
    data["memory_tree"]["nodes"][n_id] = node
    data = _log(data, f"新增节点: [{TYPE_LABEL[n_type]}] {content[:20]}")
    _atomic_save(data)
    print(f"✅ 已添加: {n_id}  保护期至: {protect_until}")
    return data

def _mem_link(data):
    print("\n--- 建立节点关系 ---")
    nodes = data["memory_tree"]["nodes"]
    active = [(nid,n) for nid,n in nodes.items() if n.get("status")=="active"]
    if len(active) < 2:
        print("❌ 活跃节点不足2个"); return data
    active.sort(key=lambda x: x[1].get("weight",0), reverse=True)
    print("活跃节点（按权重排序）:")
    for i,(nid,n) in enumerate(active,1):
        print(f"  {i}. [{TYPE_LABEL.get(n['type'],n['type'])}] W:{n['weight']:.2f} {n['content'][:35]}")
    try:
        fi = int(input("来源序号: ").strip()) - 1
        ti = int(input("目标序号: ").strip()) - 1
        from_id = active[fi][0]
        to_id = active[ti][0]
    except:
        print("❌ 输入无效"); return data
    r_map = {"1":"导致","2":"冲突"}
    print("关系: 1.导致  2.冲突")
    r_type = r_map.get(input("选择关系(1-2): ").strip())
    if not r_type:
        print("❌ 关系无效"); return data
    exists = any(r.get("target")==to_id and r.get("type")==r_type
                 for r in nodes[from_id].get("relations",[]))
    if exists:
        print("⚠️ 该关系已存在"); return data
    nodes[from_id].setdefault("relations",[]).append({"target":to_id,"type":r_type})
    if r_type == "导致":
        nodes[from_id]["weight"] = min(1.0, round(nodes[from_id]["weight"]+0.03,4))
    data = _log(data, f"建立关系: {from_id} --{r_type}--> {to_id}")
    _atomic_save(data)
    print(f"✅ 已建立: {active[fi][1]['content'][:20]} --{r_type}--> {active[ti][1]['content'][:20]}")
    return data

def _mem_decay(data):
    print("\n--- 触发记忆衰减 ---")
    nodes = data["memory_tree"]["nodes"]
    anchored = _get_anchored_ids(nodes)
    now = datetime.now()
    decayed = []
    to_archive = []
    for nid,node in nodes.items():
        if node.get("status") != "active": continue
        if node.get("type") in NO_DECAY: continue
        protect_str = node.get("protected_until","")
        if protect_str:
            try:
                if now <= datetime.strptime(protect_str,"%Y-%m-%d"):
                    continue
            except: pass
        updated_str = node.get("updated", node.get("time",""))
        try:
            updated_dt = datetime.strptime(updated_str[:19],"%Y-%m-%d %H:%M:%S")
        except: continue
        days = (now - updated_dt).days
        if days <= 0: continue
        if nid in anchored:
            days = days // 2
        original = node.get("weight",1.0)
        if days > 180:
            new_weight = round(original * 0.5, 4)
        elif days > 90:
            new_weight = round(original * 0.8, 4)
        elif days > 30:
            new_weight = round(original * 0.95, 4)
        else:
            continue
        node["weight"] = new_weight
        decayed.append((nid, original, new_weight, node["content"][:30]))
        created_str = node.get("time","")
        try:
            created_days = (now - datetime.strptime(created_str[:19],"%Y-%m-%d %H:%M:%S")).days
        except:
            created_days = 0
        no_relations = len(node.get("relations",[])) == 0 and nid not in anchored
        if new_weight < 0.3 and no_relations and created_days > 90:
            to_archive.append(nid)
    if not decayed:
        print("✅ 暂无需要衰减的节点")
    else:
        print(f"\n衰减了 {len(decayed)} 个节点：")
        for nid,old,new,content in decayed:
            anchor_mark = " 🔒锚定" if nid in anchored else ""
            print(f"  {content}  {old:.2f}→{new:.2f}{anchor_mark}")
    if to_archive:
        print(f"\n⚠️  以下节点建议归档（权重<0.3 且 无关联 且 创建>90天）：")
        for nid in to_archive:
            print(f"  {nodes[nid]['content'][:40]}")
        if input("全部标记为待归档？(y/n): ").strip() == "y":
            for nid in to_archive:
                nodes[nid]["status"] = "待归档"
            print(f"✅ 已标记 {len(to_archive)} 个")
    data = _log(data, f"触发衰减: {len(decayed)}个节点衰减，{len(to_archive)}个待归档")
    _atomic_save(data)
    return data

def _mem_view(data):
    print("\n--- 活跃记忆 ---")
    nodes = data["memory_tree"].get("nodes",{})
