def _mem_suggest(data):
    print("\n--- 维护建议 ---")
    nodes = data["memory_tree"].get("nodes",{})
    now = datetime.now()
    suggestions = []
    for nid,n in nodes.items():
        if n.get("status") == "待归档":
            suggestions.append(("归档", nid, n["content"][:35]))
    conflicts = []
    for nid,n in nodes.items():
        for r in n.get("relations",[]):
            if r.get("type") == "冲突":
                conflicts.append((nid, r["target"]))
    for a,b in conflicts:
        ca = nodes.get(a,{}).get("content","")[:20]
        cb = nodes.get(b,{}).get("content","")[:20]
        suggestions.append(("冲突", f"{a}⚡{b}", f"{ca} ⚡ {cb}"))
    for nid,n in nodes.items():
        if n.get("type") in NO_DECAY: continue
        if n.get("status") != "active": continue
        protect_str = n.get("protected_until","")
        if not protect_str: continue
        try:
            days_left = (datetime.strptime(protect_str,"%Y-%m-%d") - now).days
            if 0 <= days_left <= 7:
                suggestions.append(("即将衰减", nid, f"{n['content'][:30]} (还有{days_left}天)"))
        except: pass
    if not suggestions:
        print("✅ 暂无维护建议"); return data
    print(f"共 {len(suggestions)} 条建议：\n")
    for i,(s_type,s_id,s_content) in enumerate(suggestions,1):
        print(f"  {i}. [{s_type}] {s_content}")
    print("\n输入序号确认(逗号分隔) / a全部确认 / 回车跳过")
    choice = input("操作: ").strip()
    to_confirm = []
    if choice == "a":
        to_confirm = list(range(len(suggestions)))
    elif choice:
        try:
            to_confirm = [int(x.strip())-1 for x in choice.split(",")]
        except:
            print("❌ 输入无效")
    for idx in to_confirm:
        if idx < 0 or idx >= len(suggestions): continue
        s_type,s_id,s_content = suggestions[idx]
        if s_type == "归档":
            nodes[s_id]["status"] = "归档"
            print(f"  ✅ 已归档: {s_content}")
        elif s_type == "冲突":
            print(f"  ⚡ 冲突已确认: {s_content}")
    if to_confirm:
        data = _log(data, f"维护建议处理: {len(to_confirm)}条")
        _atomic_save(data)
    return data


